const b = $input.item.json.body || $input.item.json;
const q = $input.item.json.query || {};
const nip = b.nip || $input.item.json.headers?.['x-nip'] || '';
if (!nip) throw new Error('NIP tidak ditemukan');
if (!b.unitasetid) throw new Error('ID aset tidak ditemukan');
if (!b.tujuanpeminjaman) throw new Error('Tujuan peminjaman kosong');
return [{ json: {
  id: 'PMJ-' + Date.now(),
  userid: nip,
  unitasetid: b.unitasetid,
  tujuanpeminjaman: b.tujuanpeminjaman,
  tanggalmulai: b.tanggalmulai,
  tanggalselesai: b.tanggalselesai,
  instansi_id: b.instansi_id || q.instansi_id || 'bapperida'
} }];

