VALUES ('{{ ($json.id).toString().replace(/'/g, "''") }}', '{{ ($json.id).toString().replace(/'/g, "''") }}', '{{ ($json.userid).toString().replace(/'/g, "''") }}', '{{ ($json.unitasetid).toString().replace(/'/g, "''") }}', '{{ ($json.tujuanpeminjaman).toString().replace(/'/g, "''") }}', '{{ ($json.tanggalmulai).toString().replace(/'/g, "''") }}'::timestamp, '{{ ($json.tanggalselesai).toString().replace(/'/g, "''") }}'::timestamp, 'MENUNGGU', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '{{ ($json.instansi_id || "bapperida").toString().replace(/'/g, "''") }}')
RETURNING id, status;
